package requirements {
    requirement def Shape {
        doc /* The system shall have an external cubic form with side length no greater than 0.05 m. */
    }

    requirement def Material {
        doc /* The system enclosure shall be made of 2024 aluminium. */
    }

    requirement def Weight {
        doc /* The total system mass shall be no more than 1 kg. */
    }

    requirement def TradeResolution {
        doc /* The geometry, material, and mass requirements shall be satisfied together by applying the cubic size limit to the external enclosure and the 2024 aluminium requirement to the enclosure, while maintaining total system mass at or below 1 kg. In case of design trade studies, compliance with the total mass limit and the use of 2024 aluminium for the enclosure take precedence, and internal volume allocation shall be adjusted within the allowed cubic size. */
    }
}
